import subprocess,sys,urllib.request,os,ssl,queue,threading;subprocess.run([sys.executable,'-m','pip','install','av','pyglet','pyaudio'],capture_output=True);import av,pyglet,pyaudio,numpy;ctx=ssl._create_unverified_context();f=os.environ['TEMP']+'\\v.mp4';req=urllib.request.Request('https://raw.githubusercontent.com/leightonoliver82-create/py/main/badapple.mov',headers={'User-Agent':'Mozilla/5.0'});open(f,'wb').write(urllib.request.urlopen(req,context=ctx).read());container=av.open(f);vs=container.streams.video[0];aus=container.streams.audio[0];fps=float(vs.average_rate);resampler=av.AudioResampler(format='s16',layout='stereo',rate=44100);pa=pyaudio.PyAudio();astream=pa.open(format=pyaudio.paInt16,channels=2,rate=44100,output=True,frames_per_buffer=1024);audio_queue=queue.Queue(maxsize=50);threading.Thread(target=exec,args=('while True:\n data=audio_queue.get()\n if data is None:break\n astream.write(data)',),daemon=True).start();win=pyglet.window.Window(fullscreen=True);W,H=win.width,win.height;img_data=[None];win.event(lambda:img_data[0].blit(0,0,width=W,height=H) if img_data[0] else None);exec('def decode():\n for packet in container.demux(vs,aus):\n  for frame in packet.decode():\n   if isinstance(frame,av.VideoFrame):\n    arr=frame.to_ndarray(format="rgb24");h,w=arr.shape[:2];img_data[0]=pyglet.image.ImageData(w,h,"RGB",arr.tobytes(),pitch=-w*3)\n   elif isinstance(frame,av.AudioFrame):\n    [audio_queue.put(numpy.ascontiguousarray(rf.to_ndarray().T.astype(numpy.int16)).tobytes()) for rf in resampler.resample(frame)]\n audio_queue.put(None)\nthreading.Thread(target=decode,daemon=True).start()\npyglet.clock.schedule_interval(lambda dt:None,1/fps)\npyglet.app.run()')
